import sys, select, json, time, os, glob, subprocess
if not select.select([sys.stdin], [], [], 0.5)[0]:
    sys.exit(0)
try:
    data = json.load(sys.stdin)
except:
    sys.exit(0)
prompt = data.get('prompt', '').strip().lower()
if prompt == 'ok':
    my_pid = os.getpid()
    for p in glob.glob('/proc/[0-9]*/cmdline'):
        try:
            pid = int(p.split('/')[2])
            if pid == my_pid:
                continue
            cmd = open(p, 'rb').read().replace(b'\x00', b' ').decode()
            if 'agents/alert/alert.py' in cmd:
                os.kill(pid, 15)
        except:
            pass
    snooze = str(int(time.time()) + 300)
    subprocess.run(f'echo {snooze} > /home/cade/.alert_snoozed_until', shell=True)
    sys.stdout.write('Alert snoozed for 5 min.\n')
    sys.stdout.flush()
